-- Shuttle-to-Kick Conditioning (shuttle-to-kick-conditioning)
UPDATE coaching.exercise SET
  name = 'Shuttle-to-Kick Conditioning',
  description = 'Shuttle-to-Kick Conditioning uses acceleration, deceleration, support-foot pivot to improve a key kicking-athlete problem: Conditions the sport sequence of moving, braking, striking, and recovering without pretending that tired sloppy kicks are better training.',
  card_summary = 'Shuttle-to-Kick Conditioning is a Sustained Capacity exercise for kicking athletes that trains footwork-to-kick repeatability with direct carryover to MMA cage pressure, kickboxing combinations, soccer transition strike.',
  coach_language = 'Primary subrole: conditioning_intervals. Coach this as Sustained Capacity work: preserve the intended phase, dose the drill by quality, and connect every rep to support-leg control, hip action, trunk transfer, and safe reset behavior.',
  athlete_language = 'Brake, kick, reset, then go again.',
  movement_family = 'Footwork-to-kick repeatability',
  primary_phase_key = 'sustained_capacity',
  phase_subrole = 'conditioning_intervals',
  primary_order_slot = 'shuttle_to_kick_conditioning',
  default_sets = 4,
  default_reps = 10,
  default_work_seconds = 20,
  default_rest_seconds = 50,
  est_seconds_per_set = 70,
  movement_requirements = '{"primary_joint_actions":["acceleration","deceleration","support-foot pivot","hip flexion"],"primary_tissues":["calves","quadriceps","glutes","hip flexors"],"primary_motor_control_demands":[],"postural_shape":null,"breathing_demand":"medium","balance_demand":"medium","coordination_demand":"high","impact_level":3,"space_needed":"Open lane, mat, wall, rack, or target area with enough room to pivot, kick, strike, land, and reset safely.","sport_carryover":["MMA cage pressure","kickboxing combinations","soccer transition strike"],"kicking_constraints":["support-foot pressure","pelvis control","hip rotation or chamber","trunk organization","recoil or safe finish"]}'::jsonb,
  coaching_execution = '{"movement_description":"Perform Shuttle-to-Kick Conditioning with attention to acceleration, deceleration, support-foot pivot, then reset into a stance or position that would allow another kick, strike, or ball action.","setup":["Set up with cones, pads, partner, timer and enough open space for the athlete to move, pivot, and stop without crowding.","Explain the intended phase and quality gate before the first rep so the athlete knows whether this is access, skill, output, strength, resilience, conditioning, or restore work.","Establish stance foot pressure, rib-pelvis position, and a safe return/reset position before adding speed, load, target, or partner input.","Connect the drill to MMA cage pressure, kickboxing combinations so the athlete understands the transfer target without rushing the movement."],"execution_steps":["Begin each interval from an athletic stance with a clear start cue and defined finish/reset area.","Move with useful sport intent while keeping kick mechanics, footwork, posture, and spacing under control.","Use the rest period to recover enough that the next interval still looks like training, not survival.","Stop the block when output, recoil, braking, or technical accuracy drops below the quality gate."],"coach_cues":["Brake, kick, reset, then go again.","Own the support foot.","Ribs and pelvis stay organized.","Reset before the next rep."],"common_faults":["Chasing range or speed before control","Support foot collapsing or twisting","Leaning through the low back","Letting the kick or movement finish in a poor stance"],"breathing_cues":["Exhale to organize the ribs before effort.","Do not hold breath unless specifically bracing for a loaded strength rep.","Recover nasal or calm breathing between quality attempts."],"quality_gate":"A rep counts only if Shuttle-to-Kick Conditioning keeps pain-free range, organized breathing, clean support-foot pressure, controlled hip/trunk position, and a safe reset that supports MMA cage pressure, kickboxing combinations.","stop_signs":["pain","pinching","numbness","dizziness","loss of balance","unsafe spacing","joint twisting","breath holding","visible speed drop","sloppy recoil","loud uncontrolled landing","target accuracy collapse","unclear partner role","surprise contact","communication failure"]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["technical kicking","pad work","soccer striking","strength block","conditioning"],"pairs_well_after":["general warmup","hip and ankle access","light footwork rhythm"],"good_for_sessions":["kicking_prep","hip_access","support_leg_control","deceleration","sport_skill_transfer"],"avoid_before":[],"avoid_after":["fatiguing kick intervals before skill learning","max impact on sore groin or hamstrings","chaotic partner contact without clear roles"],"do_not_use_when":[],"coach_note":"For kickboxing/MMA/soccer sessions, place mobility and skill mapping before output, strength after speed/skill, resilience after primary work, conditioning late, and restore last."}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["Coach-filmed front/side view","Slow-motion support-foot and pelvis review","Optional pad/ball target clip"],"internal_notes":["Film the support foot and pelvis as much as the kicking leg.","Quality beats height, load, and volume.","Do not import as API snake_case without taxonomy facetId mapping."]}'::jsonb,
  updated_at = now()
WHERE slug = 'shuttle-to-kick-conditioning';

