-- Why-layer education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_works, why_it_matters, why_it_goes_here,
  programming_guidance, common_misuse, scaling_guidance
)
SELECT
  'exercise', e.slug, e.id, e.name, e.card_summary,
  e.description,
  v.why_works,
  COALESCE(v.transfer, 'Builds support-leg control, hip action, trunk transfer, and safe reset for kickboxing, MMA, and soccer striking.'),
  v.why_here,
  v.best_placement,
  v.misuse,
  v.scale_guidance
FROM (VALUES
  ('9090-hip-switch-with-reach', 'Builds controlled hip internal and external rotation so the athlete can chamber, pivot, and re-chamber without borrowing motion from the knee or low back. Kicking athletes need the swing leg, stance leg, trunk, and foot to solve a shared timing problem: create range or force, transfer it through the hip and trunk, contact the target or ball, and recover to stance. This drill isolates one link without losing the sport relationship.', 'Builds controlled hip internal and external rotation so the athlete can chamber, pivot, and re-chamber without borrowing motion from the knee or low back.', 'Belongs in Prepare & Access because it improves access, activation, or readiness with minimal fatigue before technical kicking, output, strength, or conditioning.', 'Use early after a brief temperature raise and before high-speed kicking, sparring, sprinting, strength, or ball-striking work.', 'Do not turn this into a long mobility test, passive stretch contest, or fatigue circuit. The drill should leave the athlete more ready, not tired or guarded.', 'Scale by reducing range, speed, load, reaction choices, partner pressure, impact, or total volume first. Progress only one variable at a time and only after the athlete owns the quality gate.'),
  ('half-kneeling-adductor-rockback', 'Prepares the groin and inside-leg line for high chambers, lateral kicks, checks, and soccer striking without forcing passive end range. Kicking athletes need the swing leg, stance leg, trunk, and foot to solve a shared timing problem: create range or force, transfer it through the hip and trunk, contact the target or ball, and recover to stance. This drill isolates one link without losing the sport relationship.', 'Prepares the groin and inside-leg line for high chambers, lateral kicks, checks, and soccer striking without forcing passive end range.', 'Belongs in Prepare & Access because it improves access, activation, or readiness with minimal fatigue before technical kicking, output, strength, or conditioning.', 'Use early after a brief temperature raise and before high-speed kicking, sparring, sprinting, strength, or ball-striking work.', 'Do not turn this into a long mobility test, passive stretch contest, or fatigue circuit. The drill should leave the athlete more ready, not tired or guarded.', 'Scale by reducing range, speed, load, reaction choices, partner pressure, impact, or total volume first. Progress only one variable at a time and only after the athlete owns the quality gate.'),
  ('wall-supported-hip-cars', 'Gives kickers slow ownership of the whole hip circle, exposing sticky ranges before speed, pads, sparring, or ball striking. Kicking athletes need the swing leg, stance leg, trunk, and foot to solve a shared timing problem: create range or force, transfer it through the hip and trunk, contact the target or ball, and recover to stance. This drill isolates one link without losing the sport relationship.', 'Gives kickers slow ownership of the whole hip circle, exposing sticky ranges before speed, pads, sparring, or ball striking.', 'Belongs in Prepare & Access because it improves access, activation, or readiness with minimal fatigue before technical kicking, output, strength, or conditioning.', 'Use early after a brief temperature raise and before high-speed kicking, sparring, sprinting, strength, or ball-striking work.', 'Do not turn this into a long mobility test, passive stretch contest, or fatigue circuit. The drill should leave the athlete more ready, not tired or guarded.', 'Scale by reducing range, speed, load, reaction choices, partner pressure, impact, or total volume first. Progress only one variable at a time and only after the athlete owns the quality gate.'),
  ('leg-swing-matrix', 'Raises dynamic range in the exact planes kickers need while keeping the support foot connected and the trunk organized. Kicking athletes need the swing leg, stance leg, trunk, and foot to solve a shared timing problem: create range or force, transfer it through the hip and trunk, contact the target or ball, and recover to stance. This drill isolates one link without losing the sport relationship.', 'Raises dynamic range in the exact planes kickers need while keeping the support foot connected and the trunk organized.', 'Belongs in Prepare & Access because it improves access, activation, or readiness with minimal fatigue before technical kicking, output, strength, or conditioning.', 'Use early after a brief temperature raise and before high-speed kicking, sparring, sprinting, strength, or ball-striking work.', 'Do not turn this into a long mobility test, passive stretch contest, or fatigue circuit. The drill should leave the athlete more ready, not tired or guarded.', 'Scale by reducing range, speed, load, reaction choices, partner pressure, impact, or total volume first. Progress only one variable at a time and only after the athlete owns the quality gate.'),
  ('ankle-knee-to-wall-mobilization', 'Improves the support-leg ankle position needed to pivot, plant, decelerate, and strike without collapsing through the arch or knee. Kicking athletes need the swing leg, stance leg, trunk, and foot to solve a shared timing problem: create range or force, transfer it through the hip and trunk, contact the target or ball, and recover to stance. This drill isolates one link without losing the sport relationship.', 'Improves the support-leg ankle position needed to pivot, plant, decelerate, and strike without collapsing through the arch or knee.', 'Belongs in Prepare & Access because it improves access, activation, or readiness with minimal fatigue before technical kicking, output, strength, or conditioning.', 'Use early after a brief temperature raise and before high-speed kicking, sparring, sprinting, strength, or ball-striking work.', 'Do not turn this into a long mobility test, passive stretch contest, or fatigue circuit. The drill should leave the athlete more ready, not tired or guarded.', 'Scale by reducing range, speed, load, reaction choices, partner pressure, impact, or total volume first. Progress only one variable at a time and only after the athlete owns the quality gate.'),
  ('couch-stretch-to-glute-squeeze', 'Restores hip extension and glute contribution so the support leg can stabilize while the kicking leg accelerates and recoils. Kicking athletes need the swing leg, stance leg, trunk, and foot to solve a shared timing problem: create range or force, transfer it through the hip and trunk, contact the target or ball, and recover to stance. This drill isolates one link without losing the sport relationship.', 'Restores hip extension and glute contribution so the support leg can stabilize while the kicking leg accelerates and recoils.', 'Belongs in Prepare & Access because it improves access, activation, or readiness with minimal fatigue before technical kicking, output, strength, or conditioning.', 'Use early after a brief temperature raise and before high-speed kicking, sparring, sprinting, strength, or ball-striking work.', 'Do not turn this into a long mobility test, passive stretch contest, or fatigue circuit. The drill should leave the athlete more ready, not tired or guarded.', 'Scale by reducing range, speed, load, reaction choices, partner pressure, impact, or total volume first. Progress only one variable at a time and only after the athlete owns the quality gate.'),
  ('shin-box-get-up-kicking', 'Links hip rotation, trunk orientation, and getting to stance, making it useful for MMA athletes who kick, wrestle, and recover from ground positions. Kicking athletes need the swing leg, stance leg, trunk, and foot to solve a shared timing problem: create range or force, transfer it through the hip and trunk, contact the target or ball, and recover to stance. This drill isolates one link without losing the sport relationship.', 'Links hip rotation, trunk orientation, and getting to stance, making it useful for MMA athletes who kick, wrestle, and recover from ground positions.', 'Belongs in Prepare & Access because it improves access, activation, or readiness with minimal fatigue before technical kicking, output, strength, or conditioning.', 'Use early after a brief temperature raise and before high-speed kicking, sparring, sprinting, strength, or ball-striking work.', 'Do not turn this into a long mobility test, passive stretch contest, or fatigue circuit. The drill should leave the athlete more ready, not tired or guarded.', 'Scale by reducing range, speed, load, reaction choices, partner pressure, impact, or total volume first. Progress only one variable at a time and only after the athlete owns the quality gate.'),
