-- Kicking Athletes cluster validation education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_matters, programming_guidance, common_misuse
)
VALUES (
  'validation_rule',
  'kicking_athletes_readiness',
  NULL,
  'Kicking athletes without wrong phase intent or conditioning drift',
  'Kickboxing, MMA, and soccer kicking work must follow phase order: hip access and skill mapping before output speed, strength after fresh kicking, resilience after primary work, conditioning late, restore last.',
  'The Kicking Athletes library spans hip and ankle access, chamber/pivot skill mapping, rotational and reactive kick output, single-leg and adductor strength, deceleration and lower-leg resilience, repeat kick conditioning, and restore breathing for athletes who kick, strike, or shoot repeatedly.',
  'Kicking speed, accuracy, and tissue tolerance depend on support-leg control, hip rotation, and recovery. Poor placement — speed work when hips are locked, strength after fatiguing kick intervals, or restore skipped after hard kicking — raises groin, hamstring, and low-back risk and blunts transfer.',
  'Prepare & Access opens hips, ankles, and trunk. Movement Intelligence teaches chamber, pivot, and target touch while fresh. Output stays low-volume and high-intent. Capacity builds force reserve. Resilience adds brakes and tissue capacity. Sustained Capacity handles repeat kick volume late. Restore downshifts after hard kicking blocks.',
  'Do not turn access drills into long mobility tests, program kick speed after fatiguing intervals, load groin-heavy patterns on sore adductors, or skip restore after high kick volume.'
)
ON CONFLICT (entity_type, entity_key, entity_id) DO UPDATE SET
